# Minimal Jinja2 prompt template system
from jinja2 import Environment, BaseLoader, TemplateNotFound
from dataclasses import dataclass, field
from typing import Any, Dict, Optional
import hashlib, json, datetime

@dataclass
class TemplateVersion:
    version: str
    content: str
    created_at: str
    notes: str = ""

    @property
    def hash(self) -> str:
        return hashlib.sha256(self.content.encode()).hexdigest()[:12]

class PromptTemplateRegistry:
    """Central registry for versioned Jinja2 prompt templates."""

    def __init__(self):
        self._templates: Dict[str, list[TemplateVersion]] = {}
        self._env = Environment(loader=BaseLoader())

    def register(self, name: str, content: str, notes: str = "") -> TemplateVersion:
        version_num = f"v{len(self._templates.get(name, [])) + 1}.0"
        ver = TemplateVersion(
            version=version_num,
            content=content,
            created_at=datetime.datetime.utcnow().isoformat(),
            notes=notes,
        )
        self._templates.setdefault(name, []).append(ver)
        return ver

    def get(self, name: str, version: Optional[str] = None) -> TemplateVersion:
        versions = self._templates.get(name, [])
        if not versions:
            raise KeyError(f"Template '{name}' not found")
        if version is None:
            return versions[-1]  # latest
        for v in versions:
            if v.version == version:
                return v
        raise KeyError(f"Version '{version}' of '{name}' not found")

    def render(self, name: str, variables: Dict[str, Any],
               version: Optional[str] = None) -> str:
        tv = self.get(name, version)
        tmpl = self._env.from_string(tv.content)
        return tmpl.render(**variables)

    def history(self, name: str) -> list[TemplateVersion]:
        return list(self._templates.get(name, []))


# --- Usage ---
registry = PromptTemplateRegistry()

registry.register(
    "summarize",
    "Summarize the following {{ content_type }} in {{ max_sentences }} sentences:\n\n{{ text }}",
    notes="Initial version — plain summary",
)

registry.register(
    "summarize",
    "You are an expert {{ domain }} analyst.\n"
    "Summarize the following {{ content_type }} in {{ max_sentences }} sentences, "
    "highlighting {{ focus }}.\n\n{{ text }}",
    notes="v2 — adds role framing and focus parameter",
)

prompt = registry.render("summarize", {
    "domain": "financial",
    "content_type": "earnings report",
    "max_sentences": 3,
    "focus": "revenue trends and risk factors",
    "text": "Q3 net revenue rose 12% YoY to $4.2 B ...",
})
print(prompt)
# Each version is independently addressable:
v1 = registry.render("summarize", {"content_type":"doc","max_sentences":2,"text":"..."}, version="v1.0")
print("\nv1 hash:", registry.get("summarize","v1.0").hash)
print("v2 hash:", registry.get("summarize").hash)
